    print_file_handles(list);
    printf("Count: %d\n\n", get_file_handle_count(list));
    
    printf("Removing file handle with fd=11...\n");
    remove_file_handle(list, 11);
    
    print_file_handles(list);
    printf("Count: %d\n\n", get_file_handle_count(list));
    
    printf("First cleanup...\n");
    cleanup_file_handle_list(list);
    print_file_handles(list);
    
    printf("\nSecond cleanup (should be safe)...\n");
    cleanup_file_handle_list(list);
    print_file_handles(list);
    
    printf("\nAttempting to add after cleanup (should fail)...\n");
    int result = add_file_handle(list, 13, "file4.txt");
    printf("Add result: %d (expected -1)\n", result);
    
